Given a input acceleration of 0 we return back the position at the starting point. Given an input acceleration greater than 0 we return back the position at the end of this time interval.

```js
  var velocity = 0;
  var acceleration = 0;
  var starting_vel = 0;
  var position;
  var timeinterval = 1;

  function calculate_position(v, accel, interval, init) {
    velocity += (acceleration *interval)+ starting_vel;
    starting_vel = (velocity);
    position = (((velocity * interval) * 4)/2);
    return position;
  }
```
### Test:
Tests cover the scenarios in which the function expects given an input acceleration of 0, 1 , 2 and a negative numbers to return a position at the starting point or at the end of the time interval.
```js
  describe('position', function() {
    it("should return 0 when acceleration is 0", function() {
      expect(calculate_position(0, 0, 1, 0)).toBe(0)
    });
    it("should return 2 when acceleration is 1", function() {
      expect(calculate_position(0, 1, 1, 0)).toBe(2)
    });
    it("should return 4 when acceleration is 2", function() {
      expect(calculate_position(0, 2, 1, 0)).toBe(4)
    });
    it("should return 11 when acceleration is -2.5", function() {
      expect(calculate_position(0, -2.5, 1, 0)).toBe(11)
    });
  })
```
